const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PRICE = 60;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const countByType = (items: Item[]): Map<string, number> =>
  items.reduce(
    (acc, item) => acc.set(item.type, (acc.get(item.type) ?? 0) + 1),
    new Map<string, number>(),
  );

const componentGroupPremium = (type: string, count: number): number =>
  count === COMPONENT_BLOCK_SIZE
    ? COMPONENT_BLOCK_PRICE
    : count * BASE_PREMIUM[type];

const itemsBasePremium = (items: Item[]): number => {
  const components = items.filter(isComponent);
  const others = items.filter((i) => !isComponent(i));
  const componentsBase = sum(
    [...countByType(components)].map(([type, count]) =>
      componentGroupPremium(type, count),
    ),
  );
  return componentsBase + sum(others.map(itemBasePremium));
};
